#include <cuda_runtime.h>

struct Node {
    int starting;
    int no_of_edges;
};

__global__ void BFS_1(const Node* g_graph_nodes,
                      const int* g_graph_edges,
                      char* g_graph_mask,
                      char* g_updating_graph_mask,
                      char* g_graph_visited,
                      int* g_cost,
                      const int no_of_nodes) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < no_of_nodes && g_graph_mask[tid]) {
        g_graph_mask[tid] = 0;
        int start = g_graph_nodes[tid].starting;
        int end = start + g_graph_nodes[tid].no_of_edges;
        for (int i = start; i < end; i++) {
            int id = g_graph_edges[i];
            if (!g_graph_visited[id]) {
                g_cost[id] = g_cost[tid] + 1;
                g_updating_graph_mask[id] = 1;
            }
        }
    }
}

__global__ void BFS_2(char* g_graph_mask,
                      char* g_updating_graph_mask,
                      char* g_graph_visited,
                      char* g_over,
                      const int no_of_nodes) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < no_of_nodes && g_updating_graph_mask[tid]) {
        g_graph_mask[tid] = 1;
        g_graph_visited[tid] = 1;
        *g_over = 1;
        g_updating_graph_mask[tid] = 0;
    }
}

